pre.code:
switch (tf->trapno) {
  case T_PGFLT (14):  → pgflt_handler()
  case T_SYSCALL (48): → syscall_dispatch()
  case IRQ_KBD (33):  → kbd_intr()
  case IRQ_TIMER (32): → thread_yield()
}

fault_va = rcr2();
if (pid > 0 && fault_va < VM_USERLO) {
  pending_signals[pid] |= (1 << SIGSEGV);
  return;  // no KERN_PANIC
}

c = getchar();  // from console buffer
if (c == 0x03) {  // ETX = Ctrl+C
  pending_signals[cur_pid] |= (1 << SIGINT);
  return;
}

if (pid <= 0 || pid >= NUM_IDS) return;
if (signum < 1 || signum >= NSIG) return;
pending_signals[pid] |= (1 << signum);

signals = pending_signals[pid];
for (sig = 1; sig < NSIG; sig++) {
  if (signals & (1 << sig)) {
    pending_signals[pid] &= ~(1 << sig);
    sa = &signal_actions[pid][sig];
    if (sa->sa_handler != NULL)
      deliver_signal(pid, sig, sa, tf);
    else
      default_signal_action(pid, sig, tf);
  }
}

switch (signum) {
  case SIGKILL:
  case SIGSEGV:
  case SIGINT:
    printf("[Process %d] killed by signal %d\n");
    terminate_process(pid, tf);
    break;
}

old = tcb_get_state(pid);
tcb_set_state(pid, TSTATE_DEAD);
if (old == TSTATE_READY)
  tqueue_remove(NUM_IDS, pid);
if (pid == get_curid())
  thread_exit();
